import{_ as e,o as i,c as l,a2 as t}from"./chunks/framework.LN3EJxkW.js";const u=JSON.parse('{"title":"训练、推理、参数、损失、泛化与过拟合","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"training-inference-generalization","verified":"2026-07-17T00:00:00.000Z","tags":["ai","training","inference","loss","generalization","overfitting"]},"headers":[],"relativePath":"04-ai/notes/foundations/training-inference-generalization.md","filePath":"04-ai/notes/foundations/training-inference-generalization.md","lastUpdated":1784249568000}'),n={name:"04-ai/notes/foundations/training-inference-generalization.md"};function r(s,a,o,h,d,p){return i(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="训练、推理、参数、损失、泛化与过拟合" tabindex="-1">训练、推理、参数、损失、泛化与过拟合 <a class="header-anchor" href="#训练、推理、参数、损失、泛化与过拟合" aria-label="Permalink to &quot;训练、推理、参数、损失、泛化与过拟合&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>训练是使用数据和优化算法调整模型参数，使目标损失下降的过程。参数是模型从数据中学到的数值。损失函数把预测与训练目标的差异转换为可优化数值。推理是在参数固定后，给模型输入并计算输出。泛化是模型在未见过但来自目标分布的数据上仍能完成任务。过拟合是训练数据表现改善而新数据表现不再改善或变差。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>AI 应用开发者通常不训练基础模型，但这些概念决定如何解释模型版本、评测结果和微调风险。训练损失低不等于产品任务成功；推理输出也不是从数据库检索的固定答案。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><ul><li>参数由训练更新，Prompt 不会永久修改基础模型参数。</li><li>损失是训练优化信号，不一定等于业务指标。不同损失会强调不同错误。</li><li>推理受输入、参数、解码策略和运行实现影响，可能具有随机性。</li><li>泛化只能相对于目标数据分布和任务定义讨论。</li><li>过拟合常见信号是训练损失继续下降，验证损失开始上升。</li><li>数据不代表真实场景、模型复杂度过高、重复调参和数据泄漏都会破坏泛化。</li></ul><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>应用开发中应把供应商模型视为固定版本的外部依赖：</p><ol><li>使用独立评测集验证目标任务，不用公开 Benchmark 分数替代产品评测。</li><li>Prompt 或微调迭代只查看训练/开发集，保留最终测试集。</li><li>同时记录总体指标和失败分组，例如语言、长度、权限、无答案与对抗输入。</li><li>发现训练/开发分数提高而测试或线上变差时，检查过拟合和数据分布变化。</li><li>基础模型更新后重新运行回归集，不假设新版本所有任务都更好。</li></ol><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>把参数数量当作质量的充分条件；数据、架构、训练方法和任务适配同样重要。</li><li>用训练损失直接比较采用不同目标函数的模型。</li><li>把温度调低称为消除随机性；推理服务和模型仍可能存在非确定因素。</li><li>在同一测试集上反复改 Prompt，测试集实际上已经变成开发集。</li><li>认为过拟合只发生在模型训练；Prompt 也可能被过度针对少量样例优化。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>欠拟合表示模型连训练数据中的规律也没有充分学到。正则化、更多代表性数据、降低复杂度和早停可缓解过拟合，但选择应由验证曲线和真实任务决定。</p><h2 id="训练与验证闭环" tabindex="-1">训练与验证闭环 <a class="header-anchor" href="#训练与验证闭环" aria-label="Permalink to &quot;训练与验证闭环&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;训练数据&quot;] --&gt; B[&quot;损失函数&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;优化器更新参数&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;模型版本&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;验证集选择&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[&quot;独立测试集估计泛化&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; G[&quot;推理：参数固定&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>训练损失是优化器使用的信号，产品指标是系统是否完成任务的度量。二者对象和量纲不同，不能直接互换。</p><h2 id="概念与观察信号" tabindex="-1">概念与观察信号 <a class="header-anchor" href="#概念与观察信号" aria-label="Permalink to &quot;概念与观察信号&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>改变什么</th><th>如何观察</th><th>边界</th></tr></thead><tbody><tr><td>参数</td><td>模型计算中的学习数值</td><td>检查点或模型版本</td><td>Prompt 不永久修改参数</td></tr><tr><td>损失</td><td>单批训练误差的可优化标量</td><td>训练/验证曲线</td><td>不必等于业务效用</td></tr><tr><td>推理</td><td>固定参数下计算输出</td><td>延迟、输出、Usage</td><td>仍受输入和解码影响</td></tr><tr><td>泛化</td><td>未见目标样例上的能力</td><td>独立测试与线上分组</td><td>必须说明目标分布</td></tr><tr><td>过拟合</td><td>开发表现提高而新数据退化</td><td>训练—验证差距</td><td>Prompt 也会对样例过拟合</td></tr></tbody></table><h2 id="可计算示例" tabindex="-1">可计算示例 <a class="header-anchor" href="#可计算示例" aria-label="Permalink to &quot;可计算示例&quot;">​</a></h2><p>某版本训练损失从 0.8 降至 0.2，验证损失先从 0.9 降至 0.45，后升至 0.6；同时产品测试准确率从 78% 降至 73%。继续降低训练损失不是发布依据，验证曲线提示过拟合，应回到验证损失最低附近的检查点并在独立测试集确认。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>确认训练、验证、测试按实体或时间隔离。</li><li>同时画训练与验证曲线并标注检查点。</li><li>对产品指标按语言、长度、风险和时间切片。</li><li>新模型退化时区分数据漂移、目标函数、Prompt、解码和服务实现变化。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>解释一组训练/验证曲线并选择检查点。验收：准确区分参数、损失、推理与业务指标；指出欠拟合或过拟合证据；提出独立测试与至少两个切片；不使用训练损失单独宣布产品成功。</p><h2 id="完整案例-分类模型的训练曲线与发布判断" tabindex="-1">完整案例：分类模型的训练曲线与发布判断 <a class="header-anchor" href="#完整案例-分类模型的训练曲线与发布判断" aria-label="Permalink to &quot;完整案例：分类模型的训练曲线与发布判断&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><ul><li>训练集 8,000 条、验证集 1,000 条、冻结测试集 1,000 条，按客户分组切分。</li><li>每个 Epoch 保存训练损失、验证损失和检查点。</li><li>产品门槛为测试宏平均 F1 至少 0.82，高风险类别召回率至少 0.95。</li></ul><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>Epoch 1–4 的训练损失持续下降，验证损失也从 0.90 降到 0.44。</li><li>Epoch 5–8 训练损失继续降到 0.18，但验证损失升到 0.61，出现泛化退化信号。</li><li>选择验证损失最低的 Epoch 4 检查点，而不是训练损失最低的 Epoch 8。</li><li>冻结配置后只在测试集运行一次，并按高风险类别切片。</li><li>推理记录模型检查点、预处理版本、解码规则和硬件/服务实现。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>checkpoint=epoch-4</span></span>
<span class="line"><span>test_macro_f1=0.84</span></span>
<span class="line"><span>high_risk_recall=0.93</span></span>
<span class="line"><span>decision=reject</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>总体 F1 达标但高风险召回率未达 0.95，因此不能发布。训练损失、验证损失和产品门槛分别承担不同角色。</p><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>确认同一客户和近重复文本没有跨集合。</li><li>从保存的检查点复跑推理，输出指标在预期容差内。</li><li>检查 Epoch 4 的选择发生在查看测试集之前。</li><li>在线灰度仍监测分布漂移、人工接管和高风险失败。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>若团队查看测试切片后回到训练阶段专门调整高风险类别，该测试集已经影响开发决策。应把它降级为开发证据，建立新的独立测试集；不能反复运行直到达到门槛。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>训练更新参数，推理通常在参数固定时计算输出。</li><li>损失函数是优化目标，不自动等于准确率、收入或安全。</li><li>训练曲线与验证曲线需使用相同记录粒度。</li><li>早停检查点依据预先定义的验证规则选择。</li><li>测试集只用于冻结方案后的独立判断。</li><li>泛化结论必须注明目标人群、时间和输入分布。</li><li>分布漂移会让历史测试结果失去代表性。</li><li>欠拟合表现为训练数据也无法充分拟合。</li><li>过拟合可来自模型训练、Prompt 调参或检索规则。</li><li>数据泄漏会制造虚假的泛化表现。</li><li>随机推理用多次 Trial 与分布描述。</li><li>新模型版本需重新运行回归，不假设全面提升。</li></ol><h2 id="分布、指标与因果边界" tabindex="-1">分布、指标与因果边界 <a class="header-anchor" href="#分布、指标与因果边界" aria-label="Permalink to &quot;分布、指标与因果边界&quot;">​</a></h2><p>目标分布包括用户、语言、输入长度、时间、设备、政策版本和错误成本。测试集若只来自历史活跃用户，就不能直接代表新用户；离线样例若没有真实权限和工具状态，也不能估计完整系统成功率。报告应明确采样范围和排除条件，而不是只写“未见数据”。</p><p>训练与验证曲线只能显示相关信号。验证损失上升可能来自过拟合，也可能来自数据管道、标签版本或评估实现变化；排查时先固定代码和数据哈希，再比较检查点。早停、正则化和增加数据都是候选手段，不保证在所有任务改善，必须由验证与独立测试支持。</p><p>生成模型的产品评估还包含 Prompt、检索、工具、解码和服务实现。即使基础参数不变，上述任一层变化都可能改变结果。模型卡或 Benchmark 描述的是给定条件下的能力证据，不能替代当前系统在当前数据分布上的评测。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://developers.google.com/machine-learning/crash-course/" target="_blank" rel="noreferrer">Google ML Crash Course</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/crash-course/linear-regression/loss" target="_blank" rel="noreferrer">Google ML：Loss</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/crash-course/overfitting/overfitting" target="_blank" rel="noreferrer">Google ML：Overfitting</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/glossary/" target="_blank" rel="noreferrer">Google ML Glossary</a>（访问日期：2026-07-17）</li></ul>`,46)])])}const b=e(n,[["render",r]]);export{u as __pageData,b as default};
